const KEY='portal-pareceres-v1';
const HEADER_KEY='parecer-cabecalho-professora-v1';
const CACHE_RESET_KEY='portal-pareceres-cache-reset-v3';
if(!localStorage.getItem(CACHE_RESET_KEY)){localStorage.removeItem(KEY);localStorage.removeItem('parecer-em-andamento-v2');localStorage.setItem(CACHE_RESET_KEY,'1')}
if((localStorage.getItem(KEY)||'').length>1500000){localStorage.removeItem(KEY);localStorage.removeItem('parecer-em-andamento-v2')}
const initial={classes:[{id:1,name:'Jardim II A',stage:'Educação Infantil',shift:'Manhã'}],periods:[{id:1,name:'1º semestre de 2026',start:'01/02/2026',end:'30/06/2026',active:true}],students:[],activities:[],reports:[]};
let data=JSON.parse(localStorage.getItem(KEY)||'null')||initial, filter='all';
data.classes=data.classes||initial.classes;data.periods=data.periods||initial.periods;data.students.forEach(s=>{if(!s.classId)s.classId=data.classes[0]?.id});
const $=s=>document.querySelector(s), esc=s=>String(s).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));
function save(){localStorage.setItem(KEY,JSON.stringify(data));render()}
function render(){
 const className=id=>data.classes.find(c=>c.id===id)?.name||'Turma não informada', studentClass=s=>s.className||className(s.classId), studentAge=s=>{if(!s.birthDate)return s.age||'Idade não informada';let birth=new Date(s.birthDate+'T00:00:00'),today=new Date(),age=today.getFullYear()-birth.getFullYear();if(today<new Date(today.getFullYear(),birth.getMonth(),birth.getDate()))age--;return `${age} anos`}, activePeriod=data.periods.find(p=>p.active)||data.periods[0];
 $('.term').textContent=activePeriod?activePeriod.name:'Nenhum período cadastrado';
 $('#studentCount').textContent=data.students.length;$('#activityCount').textContent=data.activities.length;$('#reportCount').textContent=data.reports.filter(r=>r.status==='done').length;$('#studentsTotal').textContent=`${data.students.length} alunos`;
 let reported=new Set(data.reports.map(r=>r.studentId)); $('#pendingList').innerHTML=data.students.filter(s=>!reported.has(s.id)).slice(0,4).map(s=>`<div class="simple-row"><div class="avatar">${s.avatar}</div><div><strong>${esc(s.name)}</strong><p>${studentAge(s)} · ${esc(studentClass(s))}</p></div><button class="text-button" onclick="generateFor(${s.id})">Gerar Documento Pedagógico →</button></div>`).join('')||'<p class="muted">Todos os pareceres da turma já foram iniciados.</p>';
 let q=$('#studentSearch')?.value?.toLowerCase()||''; $('#studentsList').innerHTML=data.students.filter(s=>s.name.toLowerCase().includes(q)).map(s=>{let r=data.reports.find(r=>r.studentId===s.id);return `<article class="student-card"><div class="avatar">${s.avatar}</div><div><strong>${esc(s.name)}</strong><p>${studentAge(s)} · ${esc(studentClass(s))}</p></div><span class="status ${r?.status==='done'?'done':''}">${r?.status==='done'?'Parecer concluído':r?'Em elaboração':'Sem parecer'}</span><button class="secondary" onclick="editStudent('${String(s.id)}')">Editar</button></article>`}).join('');
 $('#classesList').innerHTML=data.classes.map(c=>`<article class="student-card"><span class="stat-icon lilac">♧</span><div><strong>${esc(c.name)}</strong><p>${esc(c.stage)} · ${esc(c.shift)} · ${data.students.filter(s=>s.classId===c.id).length} alunos</p></div></article>`).join('')||'<p class="muted">Nenhuma turma cadastrada.</p>';
 $('#periodsList').innerHTML=data.periods.map(p=>`<article class="student-card"><span class="stat-icon orange">◷</span><div><strong>${esc(p.name)}</strong><p>${esc(p.start)} até ${esc(p.end)}</p></div><span class="status ${p.active?'done':''}">${p.active?'Período ativo':'Encerrado'}</span></article>`).join('')||'<p class="muted">Nenhum período cadastrado.</p>';
 $('#activitiesList').innerHTML=data.activities.map(a=>`<article class="activity-card"><span class="date">${esc(a.date)}</span><h2>${esc(a.title)}</h2><p>${esc(a.note)}</p><span class="tag">${esc(a.area)}</span>${a.photos?.length?`<div class="activity-photos">${a.photos.map(photo=>`<img src="${photo}" alt="Foto da atividade">`).join('')}</div>`:''}</article>`).join(''); $('#emptyActivities').style.display=data.activities.length?'none':'block';
 let reports=data.reports.filter(r=>filter==='all'||r.status===filter);$('#reportsList').innerHTML=reports.map(r=>{let s=data.students.find(s=>s.id===r.studentId),activityCount=(r.activityIds||[]).length,completed='';if(r.status==='done'&&r.deliveredAt){let d=new Date(r.deliveredAt.replace(' ','T'));completed=` · Concluído em ${d.toLocaleDateString('pt-BR')} às ${d.toLocaleTimeString('pt-BR',{hour:'2-digit',minute:'2-digit'})}`};let files=r.status==='done'?`<div class="file-links"><a href="#" onclick="downloadReport(${r.id});return false">DOCX</a><a href="#" onclick="downloadPdf(${r.id});return false">PDF</a></div>`:'';return `<div class="report-row"><div class="avatar">${s.avatar}</div><div><h3>${esc(s.name)}</h3><p>1º semestre de 2026 · ${activityCount} ${activityCount===1?'atividade vinculada':'atividades vinculadas'} · ${r.status==='done'?'Entregue':'Em elaboração'}${completed}</p>${files}</div><span class="status ${r.status==='done'?'done':''}">${r.status==='done'?'Entregue':'Rascunho'}</span><div class="actions"><button class="secondary" onclick="editReport(${r.id})">${r.status==='done'?'Ver parecer':'Continuar'}</button></div></div>`}).join('')||'<p class="muted">Nenhum parecer nesta categoria.</p>';
}
function open(content){$('#modalContent').innerHTML=content;$('#modal').showModal()}
function close(){ $('#modal').close() }
function studentForm(){open(`<h2 class="modal-title">Novo aluno</h2><p class="modal-subtitle">Inclua um aluno na turma Jardim II A.</p><div class="form-grid"><div class="field"><label>Nome completo</label><input id="name" required autofocus placeholder="Ex.: Beatriz Souza"></div><div class="field"><label>Idade</label><select id="age"><option>4 anos</option><option selected>5 anos</option><option>6 anos</option></select></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="addStudentSave()">Salvar aluno</button></div>`)}
function addStudentSave(){let name=$('#name').value.trim();if(!name)return $('#name').focus();data.students.push({id:Date.now(),name,age:$('#age').value,avatar:name.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase()});close();save()}
function activityForm(){open(`<h2 class="modal-title">Registrar atividade</h2><p class="modal-subtitle">Conte o que a turma viveu e o que você observou.</p><div class="form-grid"><div class="field"><label>Título da atividade</label><input id="activityTitle" required autofocus placeholder="Ex.: Exploração do jardim"></div><div class="field"><label>Campo de experiência</label><select id="activityArea"><option>O eu, o outro e o nós</option><option>Corpo, gestos e movimentos</option><option>Traços, sons, cores e formas</option><option>Escuta, fala, pensamento e imaginação</option><option>Espaços, tempos, quantidades, relações e transformações</option></select></div><div class="field"><label>Observações da professora</label><textarea id="activityNote" rows="4" placeholder="O que os alunos fizeram, disseram ou descobriram?"></textarea></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="addActivitySave()">Registrar atividade</button></div>`)}
function addActivitySave(){let title=$('#activityTitle').value.trim();if(!title)return $('#activityTitle').focus();data.activities.unshift({id:Date.now(),title,area:$('#activityArea').value,note:$('#activityNote').value.trim()||'Registro de vivência da turma.',date:new Date().toLocaleDateString('pt-BR',{day:'2-digit',month:'long'})});close();save()}
function generator(){if(!data.students.length)return;let options=data.students.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('');open(`<h2 class="modal-title">Gerar parecer com IA</h2><p class="modal-subtitle">A IA organizará um rascunho com base nas ${data.activities.length} atividades registradas. Seu olhar pedagógico sempre tem a palavra final.</p><div class="form-grid"><div class="field"><label>Aluno</label><select id="reportStudent">${options}</select></div><div class="field"><label>Tom do texto</label><select id="tone"><option>Acolhedor e descritivo</option><option>Objetivo e institucional</option><option>Afetivo e celebrativo</option></select></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="createDraft()">✦ Gerar rascunho</button></div>`)}
function textFor(s){let acts=data.activities.slice(0,3);let intro=`Durante o primeiro semestre, ${s.name.split(' ')[0]} participou com interesse das experiências propostas para a turma.`;if(!acts.length)return `${intro} Em suas interações cotidianas, vem construindo vínculos, ampliando sua autonomia e expressando suas ideias de diferentes maneiras. Seguiremos oferecendo tempos e espaços de escuta, brincadeira e descoberta para acompanhar seu percurso.`;let details=acts.map(a=>`na atividade “${a.title}”, ${a.note.toLowerCase().replace(/\.$/,'')}`).join('; ');return `${intro} Nos registros do período, observamos que ${details}. Essas vivências favoreceram sua curiosidade, expressão e participação no coletivo. ${s.name.split(' ')[0]} segue em processo de desenvolvimento, com importantes conquistas que serão acolhidas e acompanhadas no próximo semestre.`}
function createDraft(){let id=+$(' #reportStudent'.trim()).value,s=data.students.find(s=>s.id===id),old=data.reports.find(r=>r.studentId===id);if(old){close();return editReport(old.id)};let report={id:Date.now(),studentId:id,status:'draft',text:textFor(s)};data.reports.unshift(report);close();save();editReport(report.id)}
function generateFor(id){let s=data.students.find(s=>s.id===id),old=data.reports.find(r=>r.studentId===id);if(old)return editReport(old.id);data.reports.unshift({id:Date.now(),studentId:id,status:'draft',text:textFor(s)});save();editReport(data.reports[0].id)}
function editReport(id){let r=data.reports.find(r=>r.id===id),s=data.students.find(s=>s.id===r.studentId);open(`<h2 class="modal-title">Parecer de ${esc(s.name)}</h2><p class="modal-subtitle">Revise e ajuste o texto antes de concluir.</p><div class="field"><label>Parecer pedagógico</label><textarea id="reportText" rows="12">${esc(r.text)}</textarea></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Fechar</button><button class="secondary" type="button" onclick="saveReport(${id},'draft')">Salvar rascunho</button><button class="primary" type="button" onclick="saveReport(${id},'done')">Concluir parecer</button></div>`)}
function saveReport(id,status){let r=data.reports.find(r=>r.id===id);r.text=$('#reportText').value;r.activityIds=[...document.querySelectorAll('.report-activity:checked')].map(input=>+input.value);r.status=status;close();save();if(status==='done')downloadReport(id)}
document.querySelectorAll('.nav-item').forEach(b=>b.onclick=()=>{let target=$('#'+b.dataset.view);if(!target)return;document.querySelectorAll('.nav-item').forEach(x=>x.classList.remove('active'));b.classList.add('active');document.querySelectorAll('.view').forEach(x=>x.classList.remove('active'));target.classList.add('active');$('#headerTitle').textContent=b.textContent.trim();window.scrollTo(0,0)});
document.querySelectorAll('[data-go]').forEach(b=>b.onclick=()=>document.querySelector(`.nav-item[data-view="${b.dataset.go}"]`).click());$('#addStudent').onclick=studentForm;$('#addActivity').onclick=activityForm;$('#emptyAddActivity').onclick=activityForm;$('#openGenerator').onclick=generator;$('#studentSearch').oninput=render;document.querySelectorAll('.tab').forEach(b=>b.onclick=()=>{filter=b.dataset.filter;document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active'));b.classList.add('active');render()});$('#menuButton').onclick=()=>$('.sidebar').classList.toggle('open');render();

function studentFormV2(){let classes=data.classes.map(c=>`<option value="${c.id}">${esc(c.name)} · ${esc(c.shift)}</option>`).join('');open(`<h2 class="modal-title">Novo aluno</h2><p class="modal-subtitle">Inclua um aluno e vincule-a a uma turma já cadastrada.</p><div class="form-grid"><div class="field"><label>Nome completo</label><input id="name" required autofocus placeholder="Ex.: Beatriz Souza"></div><div class="field"><label>Idade</label><select id="age"><option>4 anos</option><option selected>5 anos</option><option>6 anos</option></select></div><div class="field"><label>Turma</label><select id="studentClass">${classes}</select></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="addStudentSaveV2()">Salvar aluno</button></div>`) }
function addStudentSaveV2(){let name=$('#name').value.trim();if(!name)return $('#name').focus();data.students.push({id:Date.now(),name,age:$('#age').value,classId:+$('#studentClass').value,avatar:name.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase()});close();save()}
function classForm(){open(`<h2 class="modal-title">Nova turma</h2><p class="modal-subtitle">Cadastre uma turma para disponibilizá-la no cadastro dos alunos.</p><div class="form-grid"><div class="field"><label>Nome da turma</label><input id="className" required autofocus placeholder="Ex.: Jardim I B"></div><div class="field"><label>Etapa</label><select id="classStage"><option>Educação Infantil</option><option>Creche</option><option>Pré-escola</option></select></div><div class="field"><label>Turno</label><select id="classShift"><option>Manhã</option><option>Tarde</option><option>Integral</option></select></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="addClassSave()">Salvar turma</button></div>`) }
function addClassSave(){let name=$('#className').value.trim();if(!name)return $('#className').focus();data.classes.push({id:Date.now(),name,stage:$('#classStage').value,shift:$('#classShift').value});close();save()}
function periodForm(){open(`<h2 class="modal-title">Novo período avaliativo</h2><p class="modal-subtitle">Este período poderá ser usado para organizar os pareceres da rede.</p><div class="form-grid"><div class="field"><label>Nome do período</label><input id="periodName" required autofocus placeholder="Ex.: 2º semestre de 2026"></div><div class="field"><label>Data de início</label><input id="periodStart" type="date"></div><div class="field"><label>Data de término</label><input id="periodEnd" type="date"></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="addPeriodSave()">Salvar período</button></div>`) }
function addPeriodSave(){let name=$('#periodName').value.trim();if(!name)return $('#periodName').focus();data.periods.forEach(p=>p.active=false);data.periods.push({id:Date.now(),name,start:$('#periodStart').value.split('-').reverse().join('/')||'Data não informada',end:$('#periodEnd').value.split('-').reverse().join('/')||'Data não informada',active:true});close();save()}
$('#addStudent').onclick=studentFormV2;$('#addClass').onclick=classForm;$('#addPeriod').onclick=periodForm;

let activityFiles=[];
function activityFormV2(){activityFiles=[];open(`<h2 class="modal-title">Registrar atividade</h2><p class="modal-subtitle">Conte o que a turma viveu e registre até três fotos da atividade.</p><div class="form-grid"><div class="field"><label>Título da atividade</label><input id="activityTitle" required autofocus placeholder="Ex.: Exploração do jardim"></div><div class="field"><label>Campo de experiência</label><select id="activityArea"><option>O eu, o outro e o nós</option><option>Corpo, gestos e movimentos</option><option>Traços, sons, cores e formas</option><option>Escuta, fala, pensamento e imaginação</option><option>Espaços, tempos, quantidades, relações e transformações</option></select></div><div class="field"><label>Observações da professora</label><textarea id="activityNote" rows="4" placeholder="O que os alunos fizeram, disseram ou descobriram?"></textarea></div><div class="field"><label>Fotos da atividade <span class="muted">(até 3 imagens)</span></label><input id="activityPhotos" type="file" accept="image/*" multiple onchange="selectActivityPhotos(this)"><div id="imagePreviews" class="image-previews"></div></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="addActivitySaveV2()">Registrar atividade</button></div>`) }
async function selectActivityPhotos(input){try{let result=await window.PortalImageEditors.processFiles(input.files,3);activityFiles=result.photos;window.currentImageEditorMode=result.mode;$('#imagePreviews').innerHTML=activityFiles.map(src=>`<img src="${src}" alt="Prévia da foto">`).join('')}catch(error){alert(error.message);input.value='';activityFiles=[];$('#imagePreviews').innerHTML=''}}
function addActivitySaveV2(){let title=$('#activityTitle').value.trim();if(!title)return $('#activityTitle').focus();Promise.all(activityFiles.map(file=>new Promise(resolve=>{let reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.readAsDataURL(file)}))).then(photos=>{data.activities.unshift({id:Date.now(),title,area:$('#activityArea').value,note:$('#activityNote').value.trim()||'Registro de vivência da turma.',photos,date:new Date().toLocaleDateString('pt-BR',{day:'2-digit',month:'long'})});close();save()})}
function generatorV2(){if(!data.students.length)return;let options=data.students.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('');open(`<h2 class="modal-title">Novo parecer</h2><p class="modal-subtitle">Escolha o aluno para iniciar um parecer em branco.</p><div class="form-grid"><div class="field"><label>Aluno</label><select id="reportStudent">${options}</select></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="createBlankDraft()">Criar parecer</button></div>`) }
function createBlankDraft(){let id=+$('#reportStudent').value,old=data.reports.find(r=>r.studentId===id);if(old){close();return editReport(old.id)};let report={id:Date.now(),studentId:id,status:'draft',text:'',activityIds:[]};data.reports.unshift(report);close();save();editReport(report.id)}
function generateFor(id){let old=data.reports.find(r=>r.studentId===id);if(old)return editReport(old.id);data.reports.unshift({id:Date.now(),studentId:id,status:'draft',text:'',activityIds:[]});save();editReport(data.reports[0].id)}
function editReport(id){let r=data.reports.find(r=>r.id===id),s=data.students.find(s=>s.id===r.studentId);r.activityIds=r.activityIds||[];let activities=data.activities.map(a=>`<label class="linked-activity"><input class="report-activity" type="checkbox" value="${a.id}" ${r.activityIds.includes(a.id)?'checked':''}><span><strong>${esc(a.title)}</strong><small>${esc(a.date)} · ${esc(a.area)}</small></span>${a.photos?.[0]?`<img src="${a.photos[0]}" alt="Foto da atividade">`:''}</label>`).join('')||'<p class="muted">Cadastre uma atividade antes de vinculá-la ao parecer.</p>';open(`<h2 class="modal-title">Parecer de ${esc(s.name)}</h2><p class="modal-subtitle">Selecione as atividades que fundamentam este parecer e escreva com seu olhar pedagógico.</p><div class="field"><label>Atividades vinculadas ao parecer</label><div class="linked-activities">${activities}</div></div><div class="field"><label>Parecer pedagógico</label><textarea id="reportText" rows="10" placeholder="Escreva aqui as observações sobre o percurso do aluno...">${esc(r.text)}</textarea><button class="ai-adjust" type="button" onclick="adjustTextWithAI()">✦ Ajustar texto com IA</button></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Fechar</button><button class="secondary" type="button" onclick="saveReport(${id},'draft')">Salvar rascunho</button><button class="primary" type="button" onclick="saveReport(${id},'done')">Concluir parecer</button></div>`) }
function adjustTextWithAI(){let field=$('#reportText'),text=field.value.trim();if(!text){field.focus();return}let adjusted=text.replace(/\s+/g,' ').replace(/\s*([,.!?;:])\s*/g,'$1 ').trim();adjusted=adjusted.charAt(0).toUpperCase()+adjusted.slice(1);if(!/[.!?]$/.test(adjusted))adjusted+='.';field.value=adjusted}
$('#addActivity').onclick=activityFormV2;$('#emptyAddActivity').onclick=activityFormV2;$('#openGenerator').onclick=generatorV2;

async function loadActivities(){try{let response=await fetch('api.php?resource=activities');if(!response.ok)throw new Error('Não foi possível carregar as atividades.');data.activities=await response.json();render()}catch(error){console.error(error)}}
async function loadClasses(){try{let response=await fetch('api.php?resource=classes');if(!response.ok)throw new Error('Não foi possível carregar as turmas.');data.classes=await response.json();render()}catch(error){console.error(error)}}
async function addActivitySaveV2(){let title=$('#activityTitle').value.trim();if(!title)return $('#activityTitle').focus();let photos=activityFiles.map(item=>String(item));let activePeriod=data.periods.find(p=>p.active)||data.periods[0];try{let response=await fetch('api.php?resource=activities',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({title,area:$('#activityArea').value,note:$('#activityNote').value.trim()||'Registro de vivência da turma.',photos,classId:1,periodId:activePeriod?.id||1,imageEditorMode:photos.length?window.currentImageEditorMode||'none':'none'})});let result=await response.json();if(!response.ok)throw new Error(result.error||'Não foi possível salvar a atividade.');close();await loadActivities()}catch(error){alert(error.message)}}
loadActivities();
loadClasses();

function studentFormV3(){open(`<h2 class="modal-title">Novo aluno</h2><p class="modal-subtitle">Inclua os dados do aluno e selecione a turma.</p><div class="form-grid"><div class="field"><label>Nome completo</label><input id="name" required autofocus placeholder="Ex.: Beatriz Souza"></div><div class="field"><label>Data de nascimento</label><input id="birthDate" type="date" required></div><div class="field"><label>Turma</label><select id="studentClass" required><option value="Maternal Único">Maternal Único</option><option value="Maternal Manhã">Maternal Manhã</option><option value="Maternal Tarde">Maternal Tarde</option></select></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="addStudentSaveV3()">Salvar aluno</button></div>`) }
function addStudentSaveV3(){let name=$('#name').value.trim(),birthDate=$('#birthDate').value;if(!name)return $('#name').focus();if(!birthDate)return $('#birthDate').focus();data.students.push({id:Date.now(),name,birthDate,className:$('#studentClass').value,avatar:name.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase()});close();save()}
$('#addStudent').onclick=studentFormV3;

