function addStudentSaveV4(){let name=$('#name').value.trim(),birthDate=$('#birthDate').value;if(!name)return $('#name').focus();if(!birthDate)return $('#birthDate').focus();data.students.push({id:Date.now(),name,birthDate,classId:+$('#studentClass').value,avatar:name.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase()});close();save()}
