function downloadReport(id){let report=data.reports.find(r=>r.id===id),student=data.students.find(s=>s.id===report.studentId),period=data.periods.find(p=>p.active)||data.periods[0],className=student.className||data.classes.find(c=>c.id===student.classId)?.name||'Turma não informada',header=JSON.parse(localStorage.getItem(HEADER_KEY)||'{}');let form=document.createElement('form');form.method='post';form.action='download_parecer.php';form.target='_blank';let fields={name:student.name,birthDate:student.birthDate||'',className,period:period?.name||'Período avaliativo',text:report.text,studentPhoto:student.photo||'',entries:JSON.stringify(report.entries||[]),headerNetwork:header.network||'',headerSchool:header.school||'',headerContact:header.contact||'',headerLogo:header.logo||''};Object.entries(fields).forEach(([name,value])=>{let input=document.createElement('input');input.type='hidden';input.name=name;input.value=value;form.appendChild(input)});document.body.appendChild(form);form.submit();form.remove()}

let wizard={};
