function wizardClose(){$('#modal').classList.remove('wizard');close()}
function generatorV4(){let options=data.students.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('');wizard={};wizardOpen(`<p class="wizard-step">ETAPA 1 DE 3 · TEXTO PRINCIPAL</p><h2 class="modal-title">Novo parecer pedagógico</h2><p class="modal-subtitle">Registre as observações mais importantes sobre o percurso do aluno.</p><div class="form-grid"><div class="field"><label>Aluno</label><select id="wizardStudent">${options}</select></div><div class="field"><label>Informações principais do parecer</label><textarea id="wizardText" placeholder="Descreva conquistas, interações, interesses, autonomia e aspectos que merecem acompanhamento..."></textarea><button class="ai-adjust" type="button" onclick="adjustTextWithAI()">✦ Ajustar texto com IA</button></div></div><div class="form-actions"><button class="secondary" type="button" onclick="wizardClose()">Voltar</button><button class="primary" type="button" onclick="wizardActivities()">Próximo</button></div>`)}
function wizardActivities(){let text=$('#wizardText').value.trim();if(!text){$('#wizardText').focus();return}wizard={studentId:+$('#wizardStudent').value,text,activityIds:[],photos:[]};let activities=data.activities.map(a=>`<label class="linked-activity"><input class="wizard-activity" type="checkbox" value="${a.id}"><span><strong>${esc(a.title)}</strong><small>${esc(a.date)} · ${esc(a.area)}</small></span>${a.photos?.[0]?`<img src="${a.photos[0]}" alt="Foto">`:''}</label>`).join('')||'<p class="muted">Nenhuma atividade cadastrada. Você pode continuar e vincular depois.</p>';wizardOpen(`<p class="wizard-step">ETAPA 2 DE 3 · ATIVIDADES E FOTOS</p><h2 class="modal-title">Vivências realizadas</h2><p class="modal-subtitle">Selecione as atividades que fundamentam o parecer e anexe até três imagens complementares.</p><div class="field"><label>Atividades vinculadas</label><div class="linked-activities">${activities}</div></div><div class="field"><label>Fotos complementares <span class="muted">(até 3 imagens)</span></label><input id="wizardPhotos" type="file" accept="image/*" multiple onchange="wizardPhotoCheck(this)"><div id="wizardPreviews" class="image-previews"></div></div><div class="form-actions"><button class="secondary" type="button" onclick="generatorV4()">Voltar</button><button class="primary" type="button" onclick="wizardReview()">Próximo</button></div>`)}
function wizardPhotoCheck(input){let files=[...input.files];if(files.length>3){alert('Adicione no máximo 3 imagens.');input.value='';return}wizard.photos=files;$('#wizardPreviews').innerHTML=files.map(f=>`<img src="${URL.createObjectURL(f)}" alt="Prévia">`).join('')}
function wizardReview(){wizard.activityIds=[...document.querySelectorAll('.wizard-activity:checked')].map(x=>+x.value);let student=data.students.find(s=>s.id===wizard.studentId),acts=data.activities.filter(a=>wizard.activityIds.includes(a.id));wizardOpen(`<p class="wizard-step">ETAPA 3 DE 3 · REVISÃO</p><h2 class="modal-title">Revise o rascunho</h2><p class="modal-subtitle">Nada será entregue ainda. Salve como rascunho ou avance para a prévia final.</p><div class="review-box"><strong>${esc(student.name)}</strong> · ${acts.length} atividade(s) vinculada(s)<br><br>${esc(wizard.text)}</div><div class="form-actions"><button class="secondary" type="button" onclick="saveWizardDraft()">Salvar rascunho</button><button class="secondary" type="button" onclick="wizardClose()">Fechar</button><button class="primary" type="button" onclick="wizardFinalize()">Finalizar parecer</button></div>`)}
function wizardReport(){let found=data.reports.find(r=>r.studentId===wizard.studentId);if(found){found.text=wizard.text;found.activityIds=wizard.activityIds;return found}let r={id:Date.now(),studentId:wizard.studentId,text:wizard.text,activityIds:wizard.activityIds,status:'draft'};data.reports.unshift(r);return r}
function saveWizardDraft(){wizardReport().status='draft';wizardClose();save()}
function wizardFinalize(){let r=wizardReport();r.status='review';save();let s=data.students.find(x=>x.id===r.studentId);wizardOpen(`<p class="wizard-step">PRÉVIA DO PARECER</p><h2 class="modal-title">Confira antes de entregar</h2><p class="modal-subtitle">Este parecer permanece em rascunho até você confirmar a entrega.</p><div class="review-box"><strong>${esc(s.name)}</strong><br><br>${esc(r.text)}</div><div class="form-actions"><button class="secondary" type="button" onclick="wizardClose()">Fechar</button><button class="primary" type="button" onclick="deliverReport(${r.id})">Entregar parecer</button></div>`)}
function deliverReport(id){let r=data.reports.find(x=>x.id===id);r.status='done';r.deliveredAt=new Date().toISOString();clearWizard();wizardClose();save();downloadReport(id);setTimeout(()=>downloadPdf(id),400)}
function downloadPdf(id){let r=data.reports.find(x=>x.id===id),s=data.students.find(x=>String(x.id)===String(r.studentId));let form=document.createElement('form');form.method='post';form.action='download_pdf.php';form.target='_blank';[['name',s.name],['text',r.text]].forEach(([name,value])=>{let input=document.createElement('input');input.type='hidden';input.name=name;input.value=value;form.appendChild(input)});document.body.appendChild(form);form.submit();form.remove()}
$('#openGenerator').onclick=generatorV4;

const WIZARD_KEY='parecer-em-andamento-v2';
function persistWizard(){localStorage.setItem(WIZARD_KEY,JSON.stringify(wizard))}
function clearWizard(){localStorage.removeItem(WIZARD_KEY)}
function wizardStart(newRegistration=false,draft=null){let options=data.students.map(s=>`<option value="${s.id}">${esc(s.name)}</option>`).join('');if(newRegistration){clearWizard();wizard={}}else if(draft){wizard=draft}else{let saved=JSON.parse(localStorage.getItem(WIZARD_KEY)||'null');wizard=saved||{}}wizardOpen(`<p class="wizard-step">ETAPA 1 DE 3 · TEXTO PRINCIPAL</p><h2 class="modal-title">Novo parecer pedagógico</h2><p class="modal-subtitle">Registre as observações mais importantes. O rascunho é salvo automaticamente neste dispositivo.</p><div class="form-grid"><div class="field"><label>Aluno</label><select id="wizardStudent" onchange="bufferStepOne()">${options}</select></div><div class="field"><label>Informações principais do parecer</label><textarea id="wizardText" oninput="bufferStepOne()" placeholder="Descreva conquistas, interações, interesses, autonomia e aspectos que merecem acompanhamento...">${esc(wizard.text||'')}</textarea><button class="ai-adjust" type="button" onclick="adjustTextWithAI();bufferStepOne()">✦ Ajustar texto com IA</button></div></div><div class="form-actions"><button class="secondary" type="button" onclick="wizardClose()">Voltar</button><button class="secondary" type="button" onclick="saveInitialDraft()">Salvar rascunho</button><button class="primary" type="button" onclick="wizardActivitiesV2()">Próximo</button></div>`);if(wizard.studentId)$('#wizardStudent').value=wizard.studentId}
function bufferStepOne(){let student=$('#wizardStudent'),text=$('#wizardText');if(student)wizard.studentId=student.value;if(text)wizard.text=text.value;persistWizard()}
function wizardActivitiesV2(){if($('#wizardText'))bufferStepOne();if(!wizard.text?.trim())return wizardStart();let activities=data.activities.map(a=>`<label class="linked-activity"><input class="wizard-activity" type="checkbox" value="${a.id}" ${(wizard.activityIds||[]).includes(a.id)?'checked':''}><span><strong>${esc(a.title)}</strong><small>${esc(a.date)} · ${esc(a.area)}</small></span>${a.photos?.[0]?`<img src="${a.photos[0]}" alt="Foto">`:''}</label>`).join('')||'<p class="muted">Nenhuma atividade cadastrada.</p>';let previews=(wizard.photos||[]).map(src=>`<img src="${src}" alt="Prévia">`).join('');wizardOpen(`<p class="wizard-step">ETAPA 2 DE 3 · ATIVIDADES E FOTOS</p><h2 class="modal-title">Vivências realizadas</h2><p class="modal-subtitle">Selecione atividades já cadastradas ou adicione uma nova vivência.</p><div class="field"><label>Atividades cadastradas</label><div class="linked-activities">${activities}</div><button class="ai-adjust" type="button" onclick="useRegisteredActivities()">+ Usar atividades selecionadas no parecer</button></div><div class="field"><label>Fotos da atividade <span class="muted">(até 3 imagens)</span></label><label id="wizardDropzone" class="dropzone" ondragover="wizardDrag(event)" ondragleave="wizardLeave()" ondrop="wizardDrop(event)"><strong>Arraste as imagens aqui</strong><span>ou clique para escolher arquivos</span><input id="wizardPhotos" type="file" accept="image/*" multiple onchange="wizardPhotoCheck(this)"></label><div id="wizardPreviews" class="image-previews">${previews}</div></div><div class="field"><label>Informações sobre a brincadeira ou as fotos</label><textarea id="wizardPhotoNote" rows="4" oninput="bufferStepTwo()" placeholder="Descreva o que aconteceu, o que o aluno explorou ou demonstrou nas imagens...">${esc(wizard.photoNote||'')}</textarea></div><div class="form-actions"><button class="secondary" type="button" onclick="wizardStart()">Voltar</button><button class="secondary" type="button" onclick="saveDraftEverywhere()">Salvar rascunho</button><button class="primary" type="button" onclick="wizardReviewV2()">Próximo</button></div>`)}
function wizardDrag(e){e.preventDefault();$('#wizardDropzone').classList.add('drag')};function wizardLeave(){$('#wizardDropzone').classList.remove('drag')};function wizardDrop(e){e.preventDefault();wizardLeave();let input=$('#wizardPhotos');input.files=e.dataTransfer.files;wizardPhotoCheck(input)}
function bufferStepTwo(){let note=$('#wizardPhotoNote');let activities=document.querySelectorAll('.wizard-activity');if(activities.length)wizard.activityIds=[...document.querySelectorAll('.wizard-activity:checked')].map(x=>+x.value);if(note)wizard.photoNote=note.value;persistWizard()}
function wizardReviewV2(){bufferStepTwo();let s=data.students.find(x=>x.id===wizard.studentId),acts=data.activities.filter(a=>(wizard.activityIds||[]).includes(a.id));wizardOpen(`<p class="wizard-step">ETAPA 3 DE 3 · REVISÃO</p><h2 class="modal-title">Revise o rascunho</h2><div class="review-box"><strong>${esc(s.name)}</strong> · ${acts.length} atividade(s) vinculada(s)<br><br>${esc(wizard.text)}${wizard.photoNote?`<br><br><strong>Vivências registradas:</strong><br>${esc(wizard.photoNote)}`:''}</div><div class="form-actions"><button class="secondary" type="button" onclick="wizardActivitiesV2()">Adicionar mais</button><button class="secondary" type="button" onclick="saveWizardDraft()">Salvar rascunho</button><button class="primary" type="button" onclick="wizardFinalizeV2()">Finalizar parecer</button></div>`)}
function wizardFinalizeV2(){bufferStepTwo();let report=wizardReport();report.status='review';report.photoNote=wizard.photoNote||'';save();let student=data.students.find(x=>x.id===report.studentId);wizardOpen(`<p class="wizard-step">PRÉVIA FINAL</p><h2 class="modal-title">Parecer pronto para entrega</h2><p class="modal-subtitle">Confira o conteúdo. Ele continua como rascunho até a confirmação abaixo.</p><div class="review-box"><strong>${esc(student.name)}</strong><br><br>${esc(report.text)}${report.photoNote?`<br><br><strong>Vivências registradas:</strong><br>${esc(report.photoNote)}`:''}</div><div class="form-actions"><button class="secondary" type="button" onclick="wizardReviewV2()">Voltar para edição</button><button class="primary" type="button" onclick="deliverReport(${report.id})">Entregar parecer</button></div>`)}
$('#openGenerator').onclick=()=>wizardStart(true);

function fileAsDataUrl(file){return new Promise((resolve,reject)=>{let reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=reject;reader.readAsDataURL(file)})}
async function wizardPhotoCheck(input){try{let result=await window.PortalImageEditors.processFiles(input.files,3);wizard.photos=result.photos;wizard.imageEditorMode=result.mode;persistWizard();$('#wizardPreviews').innerHTML=wizard.photos.map(src=>`<img src="${src}" alt="Prévia">`).join('')}catch(error){alert(error.message||'Não foi possível ler uma das imagens.');input.value=''}}
function wizardReport(){let found=data.reports.find(r=>r.studentId===wizard.studentId);let payload={text:wizard.text,activityIds:wizard.activityIds||[],photoNote:wizard.photoNote||'',photos:wizard.photos||[]};if(found){Object.assign(found,payload);return found}let report={id:Date.now(),studentId:wizard.studentId,status:'draft',...payload};data.reports.unshift(report);return report}
function editReport(id){let report=data.reports.find(r=>r.id===id);if(!report)return;let draft={studentId:report.studentId,text:report.text||'',activityIds:[],photoNote:'',photos:[],entries:report.entries||[{activityIds:report.activityIds||[],photoNote:report.photoNote||'',photos:report.photos||[]}]};wizard=draft;persistWizard();wizardStart(false,draft)}

function wizardEntries(){return [...(wizard.entries||[]),{activityIds:wizard.activityIds||[],photoNote:wizard.photoNote||'',photos:wizard.photos||[]}].map(item=>({...item,activityIds:item.activityIds||[],photos:item.photos||[],photoNote:item.photoNote||''})).filter(item=>item.activityIds.length||item.photoNote||item.photos.length)}
function wizardAddMore(){bufferStepTwo();let current={activityIds:wizard.activityIds||[],photoNote:wizard.photoNote||'',photos:wizard.photos||[]};if(current.activityIds.length||current.photoNote||current.photos.length){wizard.entries=[...(wizard.entries||[]),current]};wizard.activityIds=[];wizard.photoNote='';wizard.photos=[];persistWizard();wizardActivitiesV2()}
function importSelectedRegisteredActivities(){let selected=(wizard.activityIds||[]).map(String);let existing=new Set((wizard.entries||[]).flatMap(entry=>(entry.activityIds||[]).map(String)));let additions=data.activities.filter(activity=>selected.includes(String(activity.id))&&!existing.has(String(activity.id))).map(activity=>({activityIds:[activity.id],photoNote:activity.note||activity.title,photos:activity.photos||[]}));if(additions.length)wizard.entries=[...(wizard.entries||[]),...additions];wizard.activityIds=[];return additions.length}
function useRegisteredActivities(){bufferStepTwo();let count=importSelectedRegisteredActivities();if(!count)return alert('Selecione uma atividade ainda não adicionada.');persistWizard();alert(`${count} atividade(s) adicionada(s) ao parecer.`);wizardReviewV2()}
function wizardReviewV2(){bufferStepTwo();let s=data.students.find(x=>x.id===wizard.studentId),entries=wizardEntries(),activityTotal=entries.reduce((sum,item)=>sum+item.activityIds.length,0),images=entries.flatMap(item=>item.photos).map(src=>`<img src="${src}" alt="Foto da atividade">`).join('');wizardOpen(`<p class="wizard-step">ETAPA 3 DE 3 · REVISÃO</p><h2 class="modal-title">Revise o rascunho</h2><div class="review-box"><strong>${esc(s.name)}</strong> · ${activityTotal} atividade(s) vinculada(s)<br><br>${esc(wizard.text)}${entries.map(item=>item.photoNote?`<br><br><strong>Vivências registradas:</strong><br>${esc(item.photoNote)}`:'').join('')}</div>${images?`<div class="activity-photos">${images}</div>`:''}<div class="form-actions"><button class="secondary" type="button" onclick="wizardAddMore()">Adicionar mais</button><button class="secondary" type="button" onclick="saveWizardDraft()">Salvar rascunho</button><button class="primary" type="button" onclick="wizardFinalizeV2()">Finalizar parecer</button></div>`)}
function wizardReport(){let entries=wizardEntries(),activityIds=[...new Set(entries.flatMap(item=>item.activityIds))],photos=entries.flatMap(item=>item.photos),photoNote=entries.map(item=>item.photoNote).filter(Boolean).join('\n\n'),finalText=typeof configuredFinalText==='function'?configuredFinalText():'';let found=data.reports.find(r=>String(r.studentId)===String(wizard.studentId)),payload={text:wizard.text,activityIds,photoNote,photos,entries,useFinalText:!!wizard.useFinalText,finalText:wizard.useFinalText?(wizard.finalText||finalText):''};if(found){Object.assign(found,payload);return found}let report={id:Date.now(),studentId:wizard.studentId,status:'draft',...payload};data.reports.unshift(report);return report}

function documentDraftHtml(){let main=(wizard.text||'').split(/\n{2,}/).filter(Boolean).map(part=>`<p>${esc(part)}</p>`).join('');let entries=wizardEntries().map(item=>{let note=item.photoNote?`<p>${esc(item.photoNote)}</p>`:'';let photos=item.photos?.length?`<div class="activity-photos">${item.photos.map(src=>`<img src="${src}" alt="Foto da vivência">`).join('')}</div>`:'';return `<section class="document-entry">${note}${photos}</section>`}).join('');return `${main}${entries}`}
function wizardReviewV2(){bufferStepTwo();let student=data.students.find(x=>x.id===wizard.studentId);wizardOpen(`<p class="wizard-step">ETAPA 3 DE 3 · REVISÃO</p><h2 class="modal-title">Rascunho do documento</h2><p class="modal-subtitle">Prévia formatada para o documento final.</p><div class="review-box"><strong>${esc(student.name)}</strong>${documentDraftHtml()}</div><div class="form-actions"><button class="secondary" type="button" onclick="wizardActivitiesV2()">Voltar</button><button class="secondary" type="button" onclick="wizardAddMore()">Adicionar mais</button><button class="secondary" type="button" onclick="saveWizardDraft()">Salvar rascunho</button><button class="primary" type="button" onclick="wizardFinalizeV3()">Finalizar parecer</button></div>`)}
function wizardFinalizeV3(){try{bufferStepTwo();let report=wizardReport();report.status='review';try{save()}catch(error){console.warn('Rascunho muito grande para o armazenamento local.',error);render()}let student=data.students.find(x=>x.id===report.studentId);wizardOpen(`<p class="wizard-step">PRÉVIA FINAL</p><h2 class="modal-title">Parecer pronto para entrega</h2><p class="modal-subtitle">Confira a versão que será entregue. Ela continua como rascunho até a confirmação.</p><div class="review-box"><strong>${esc(student.name)}</strong>${documentDraftHtml()}</div><div class="form-actions"><button class="secondary" type="button" onclick="wizardReviewV2()">Voltar para edição</button><button class="primary" type="button" onclick="deliverReport(${report.id})">Entregar parecer</button></div>`)}catch(error){console.error(error);alert('Não foi possível finalizar o parecer. Verifique os campos preenchidos e tente novamente.')}}

async function wizardFinalizeV3(){try{bufferStepTwo();let report=wizardReport(),student=data.students.find(x=>String(x.id)===String(report.studentId));let response=await fetch('api.php?resource=reports',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({student:{name:student.name,birthDate:student.birthDate||'',classId:student.classId||1},text:report.text,activityIds:report.activityIds,entries:report.entries,imageEditorMode:wizard.imageEditorMode||'none'})});let result=await response.json();if(!response.ok)throw new Error(result.error||'Falha ao salvar no banco.');report.databaseId=result.id;report.status='review';save();wizardOpen(`<p class="wizard-step">PRÉVIA FINAL</p><h2 class="modal-title">Parecer pronto para entrega</h2><p class="modal-subtitle">Rascunho salvo no banco de dados. Confira antes de entregar.</p><div class="review-box">${configuredHeaderHtml()}${studentDocumentHeader(student)}${documentDraftHtml()}</div><div class="form-actions"><button class="secondary" type="button" onclick="wizardReviewV2()">Voltar para edição</button><button class="primary" type="button" onclick="deliverReport(${report.id})">Entregar parecer</button></div>`)}catch(error){console.error(error);alert(error.message)}}

function compactForStorage(value){return JSON.parse(JSON.stringify(value,(key,item)=>key==='photos'||key==='photo'?'':item))}
function save(){try{localStorage.setItem(KEY,JSON.stringify(compactForStorage(data)))}catch(error){console.warn('Não foi possível salvar a cópia local.',error)}render()}
function persistWizard(){try{localStorage.setItem(WIZARD_KEY,JSON.stringify(compactForStorage(wizard)))}catch(error){console.warn('Rascunho local sem imagens.',error)}}
try{localStorage.setItem(KEY,JSON.stringify(compactForStorage(data)))}catch(error){console.warn(error)}

async function loadReports(){try{let response=await fetch('api.php?resource=reports&summary=1');if(!response.ok)throw new Error();let reports=await response.json();reports=reports.map(r=>({...r,status:['done','concluido','concluído','entregue'].includes(String(r.status).toLowerCase())?'done':'draft'}));reports.forEach(r=>{let student=data.students.find(s=>String(s.id)===String(r.studentId));if(!student){student={id:r.studentId,name:r.name,birthDate:r.birthDate,classId:r.classId,avatar:r.name.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase()};data.students.push(student)}});data.reports=reports;render()}catch(error){console.warn('Não foi possível carregar os pareceres.',error)}}
async function deliverReport(id){let report=data.reports.find(x=>x.id===id),databaseId=report?.databaseId||report?.id;if(!databaseId)return alert('Este parecer ainda não foi salvo no banco de dados.');try{let response=await fetch('api.php?resource=reports',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({deliverId:databaseId})});let result=await response.json();if(!response.ok||!result.ok)throw new Error(result.error||'Falha ao entregar.');report.status='done';report.deliveredAt=new Date().toISOString();clearWizard();wizardClose();save();downloadReport(report.id);setTimeout(()=>downloadPdf(report.id),400);setTimeout(()=>loadReports(),1200)}catch(error){console.error(error);alert(error.message||'Não foi possível concluir o parecer no banco de dados.')}}
async function saveInitialDraft(){bufferStepOne();let student=data.students.find(s=>String(s.id)===String(wizard.studentId));if(!student)return;try{let response=await fetch('api.php?resource=reports',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({draft:true,student:{name:student.name,birthDate:student.birthDate||'',classId:student.classId||1},text:wizard.text||'',activityIds:[],entries:[],useFinalText:!!wizard.useFinalText,finalText:wizard.useFinalText?(wizard.finalText||''):'',imageEditorMode:wizard.imageEditorMode||'none'})});let result=await response.json();if(!response.ok)throw new Error(result.error||'Erro ao salvar.');wizard.databaseId=result.id;persistWizard();alert('Rascunho salvo com sucesso.')}catch(error){alert(error.message)}}
async function saveDraftEverywhere(){try{if($('#wizardText'))bufferStepOne();if($('#wizardPhotoNote'))bufferStepTwo();let student=data.students.find(s=>String(s.id)===String(wizard.studentId));if(!student)throw new Error('Selecione um aluno antes de salvar.');let entries=wizardEntries(),activityIds=[...new Set(entries.flatMap(entry=>entry.activityIds||[]))],finalText=typeof configuredFinalText==='function'?configuredFinalText():'';let response=await fetch('api.php?resource=reports',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({draft:true,student:{name:student.name,birthDate:student.birthDate||'',classId:student.classId||1},text:wizard.text||'',activityIds,entries,useFinalText:!!wizard.useFinalText,finalText:wizard.useFinalText?(wizard.finalText||finalText):'',imageEditorMode:wizard.imageEditorMode||'none'})});let result=await response.json();if(!response.ok)throw new Error(result.error||'Erro ao salvar o rascunho.');let report=data.reports.find(r=>String(r.studentId)===String(wizard.studentId));if(!report){report={id:Date.now(),studentId:wizard.studentId,status:'draft'};data.reports.unshift(report)}Object.assign(report,{databaseId:result.id,text:wizard.text||'',activityIds,entries,useFinalText:!!wizard.useFinalText,finalText:wizard.useFinalText?(wizard.finalText||finalText):'',photoNote:entries.map(e=>e.photoNote).filter(Boolean).join('\n\n')});persistWizard();save();alert('Rascunho salvo com sucesso no banco de dados.')}catch(error){console.error(error);alert(error.message)}}
async function saveWizardDraft(){await saveDraftEverywhere()}
loadReports();
window.addEventListener('focus',loadReports);

function studentFormV5(){let options=data.classes.map(c=>`<option value="${c.id}">${esc(c.name)} · ${esc(c.shift)}</option>`).join('');open(`<h2 class="modal-title">Novo aluno</h2><p class="modal-subtitle">Inclua os dados e uma foto para identificação no parecer.</p><div class="form-grid"><div class="field"><label>Nome completo</label><input id="name" required autofocus></div><div class="field"><label>Data de nascimento</label><input id="birthDate" type="date" required></div><div class="field"><label>Turma</label><select id="studentClass" required>${options}</select></div><div class="field"><label>Foto do aluno</label><input id="studentPhoto" type="file" accept="image/*"></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="addStudentSaveV5()">Salvar aluno</button></div>`)}
async function addStudentSaveV5(){let name=$('#name').value.trim(),birthDate=$('#birthDate').value,file=$('#studentPhoto').files[0];if(!name)return $('#name').focus();if(!birthDate)return $('#birthDate').focus();let photo=file?await fileAsDataUrl(file):'';try{let response=await fetch('api.php?resource=children',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name,birthDate,classId:+$('#studentClass').value,photo})});let result=await response.json();if(!response.ok)throw new Error(result.error||'Não foi possível salvar o aluno.');close();await loadChildren()}catch(error){alert(error.message)}}
function studentDocumentHeader(student){let className=student.className||data.classes.find(c=>c.id===student.classId)?.name||'Turma não informada',birth=student.birthDate?student.birthDate.split('-').reverse().join('/'):'Não informado';return `<div class="document-student"><div><p><b>NOME:</b> ${esc(student.name)}</p><p><b>D.N.:</b> ${esc(birth)}</p><p><b>TURMA:</b> ${esc(className)} <span style="margin-left:90px"><b>ANO:</b>${new Date().getFullYear()}</span></p></div>${student.photo?`<img src="${student.photo}" alt="Foto do aluno">`:''}</div>`}
function configuredHeaderHtml(){let header=JSON.parse(localStorage.getItem(HEADER_KEY)||'{}'),text=[header.network,header.school,header.contact].filter(Boolean).join('\n');return text||header.logo?`<div class="document-header"><div>${esc(text)}</div>${header.logo?`<img src="${header.logo}" alt="Logo institucional">`:''}</div>`:''}
function wizardReviewV2(){bufferStepTwo();importSelectedRegisteredActivities();persistWizard();let student=data.students.find(x=>String(x.id)===String(wizard.studentId));if(!student)return alert('Não foi possível localizar o aluno deste parecer.');wizardOpen(`<p class="wizard-step">ETAPA 3 DE 3 · REVISÃO</p><h2 class="modal-title">Rascunho do documento</h2><p class="modal-subtitle">Prévia formatada para o documento final.</p><div class="review-box">${configuredHeaderHtml()}${studentDocumentHeader(student)}${documentDraftHtml()}</div><div class="form-actions"><button class="secondary" type="button" onclick="wizardActivitiesV2()">Voltar</button><button class="secondary" type="button" onclick="wizardAddMore()">Adicionar mais</button><button class="secondary" type="button" onclick="saveWizardDraft()">Salvar rascunho</button><button class="primary" type="button" onclick="wizardFinalizeV3()">Finalizar parecer</button></div>`)}
$('#addStudent').onclick=studentFormV5;

function editStudent(id){let student=data.students.find(s=>String(s.id)===String(id));if(!student)return;let options=data.classes.map(c=>`<option value="${c.id}" ${String(c.id)===String(student.classId)?'selected':''}>${esc(c.name)} · ${esc(c.shift)}</option>`).join('');open(`<h2 class="modal-title">Editar aluno</h2><p class="modal-subtitle">Atualize os dados cadastrais e a foto de identificação.</p><div class="form-grid"><div class="field"><label>Nome completo</label><input id="editStudentName" value="${esc(student.name)}" required></div><div class="field"><label>Data de nascimento</label><input id="editStudentBirth" type="date" value="${esc(student.birthDate||'')}"></div><div class="field"><label>Turma</label><select id="editStudentClass">${options}</select></div><div class="field"><label>Nova foto <span class="muted">(opcional)</span></label><input id="editStudentPhoto" type="file" accept="image/*"></div></div><div class="form-actions"><button class="secondary" type="button" onclick="document.querySelector('#modal').close()">Cancelar</button><button class="primary" type="button" onclick="saveStudentEdit('${String(student.id)}')">Salvar alterações</button></div>`)}
async function saveStudentEdit(id){let student=data.students.find(s=>String(s.id)===String(id));if(!student)return;let name=$('#editStudentName').value.trim(),file=$('#editStudentPhoto').files[0];if(!name)return $('#editStudentName').focus();student.name=name;student.birthDate=$('#editStudentBirth').value;student.classId=+$('#editStudentClass').value;student.avatar=name.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase();if(file)student.photo=await fileAsDataUrl(file);close();save()}
async function saveStudentEdit(id){let student=data.students.find(s=>String(s.id)===String(id));if(!student)return;let name=$('#editStudentName').value.trim(),file=$('#editStudentPhoto').files[0];if(!name)return $('#editStudentName').focus();if(file)student.photo=await fileAsDataUrl(file);let response=await fetch('api.php?resource=children',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({databaseId:student.databaseId||String(student.id).replace('db-',''),name,birthDate:$('#editStudentBirth').value,classId:+$('#editStudentClass').value,photo:student.photo||''})});let result=await response.json();if(!response.ok)return alert(result.error||'Não foi possível salvar o aluno.');Object.assign(student,{id:'db-'+result.id,databaseId:result.id,name,birthDate:$('#editStudentBirth').value,classId:+$('#editStudentClass').value,avatar:name.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase()});close();save()}
async function loadChildren(){try{let response=await fetch('api.php?resource=children');if(!response.ok)return;let children=await response.json();data.students=children.map(child=>({...child,avatar:child.name.split(/\s+/).slice(0,2).map(x=>x[0]).join('').toUpperCase()}));render()}catch(error){console.warn(error)}}
loadChildren();

async function loadHeaderSettings(){let settings=JSON.parse(localStorage.getItem(HEADER_KEY)||'{}');try{let response=await fetch('api.php?resource=header-settings');if(response.ok){settings=await response.json();localStorage.setItem(HEADER_KEY,JSON.stringify(settings))}}catch(error){console.warn('Nao foi possivel carregar o cabecalho do usuario.',error)}$('#headerNetwork').value=settings.network||'';$('#headerSchool').value=settings.school||'';$('#headerContact').value=settings.contact||'';$('#headerLogoPreview').innerHTML=settings.logo?`<img src="${settings.logo}" alt="Logo">`:''}
$('#saveHeaderSettings').onclick=async()=>{let logoFile=$('#headerLogo').files[0],old=JSON.parse(localStorage.getItem(HEADER_KEY)||'{}'),logo=old.logo||'';if(logoFile)logo=await fileAsDataUrl(logoFile);let settings={network:$('#headerNetwork').value.trim(),school:$('#headerSchool').value.trim(),contact:$('#headerContact').value.trim(),logo};let response=await fetch('api.php?resource=header-settings',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(settings)});let result=await response.json().catch(()=>({}));if(!response.ok)return alert(result.error||'Nao foi possivel salvar o cabecalho.');localStorage.setItem(HEADER_KEY,JSON.stringify(settings));loadHeaderSettings();alert('Cabeçalho salvo com sucesso.')};
loadHeaderSettings();

function editReport(id){let report=data.reports.find(r=>String(r.id)===String(id));if(!report)return;let draft={studentId:report.studentId,text:report.text||'',activityIds:[],photoNote:'',photos:[],entries:report.entries||[{activityIds:report.activityIds||[],photoNote:report.photoNote||'',photos:report.photos||[]}]};wizard=draft;let student=data.students.find(s=>String(s.id)===String(report.studentId));if(report.status==='done'){wizardOpen(`<p class="wizard-step">PARECER ENTREGUE</p><h2 class="modal-title">Revisão do parecer</h2><p class="modal-subtitle">Visualização completa do documento entregue.</p><div class="review-box">${configuredHeaderHtml()}${studentDocumentHeader(student)}${documentDraftHtml()}</div><div class="form-actions"><button class="secondary" type="button" onclick="wizardClose()">Fechar</button><button class="secondary" type="button" onclick="reopenReport(${report.id})">Reabrir parecer</button><button class="secondary" type="button" onclick="downloadPdf(${report.id})">Baixar PDF</button><button class="primary" type="button" onclick="downloadReport(${report.id})">Baixar DOCX</button></div>`);return}persistWizard();wizardStart(false,draft)}
async function reopenReport(id){let report=data.reports.find(r=>String(r.id)===String(id));try{let response=await fetch('api.php?resource=reports',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({reopenId:report.databaseId||report.id})});let result=await response.json();if(!response.ok||!result.ok)throw new Error(result.error||'Não foi possível reabrir o parecer.');await loadReports();wizardClose();editReport(id)}catch(error){alert(error.message)}}
